/**
 * Sliding Window Rate Limiter for Express.js
 * ------------------------------------------
 * A TRUE sliding window: every request's timestamp is recorded, and on each
 * incoming request we discard timestamps older than `windowMs` from "now".
 * The decision is made against the count of timestamps remaining inside the
 * trailing window — there is no fixed bucket that resets on an interval, so a
 * burst at the boundary cannot exploit a reset.
 *
 * NOTE on `req.ip` behind proxies:
 *   Express derives `req.ip` from the socket address unless `trust proxy` is
 *   enabled. Behind a reverse proxy / load balancer (Nginx, Cloudflare, ELB),
 *   the socket address is the proxy's, so every client collapses to one key and
 *   the limiter throttles everyone together. Enable trust proxy so Express reads
 *   the client IP from the `X-Forwarded-For` header:
 *
 *       app.set('trust proxy', 1); // or true / a subnet / a function
 *
 *   Only trust proxy when you actually run behind a proxy that sets/sanitizes
 *   XFF — otherwise clients can spoof the header and evade limiting.
 */

/**
 * @param {Object}  [options]
 * @param {number}  [options.windowMs=60000]   Window size in milliseconds.
 * @param {number}  [options.maxRequests=100]  Max requests allowed per window.
 * @param {number}  [options.cleanupMs=60000]  Sweep interval for stale IP entries.
 * @param {(req)=>string} [options.keyGenerator] Derive the client key (default: req.ip).
 * @returns {Function & { close: () => void }} Express middleware with a close() method.
 */
function createRateLimiter(options = {}) {
  const {
    windowMs = 60000,
    maxRequests = 100,
    cleanupMs = 60000,
    keyGenerator = (req) => req.ip,
  } = options;

  if (!Number.isFinite(windowMs) || windowMs <= 0) {
    throw new TypeError('windowMs must be a positive number');
  }
  if (!Number.isInteger(maxRequests) || maxRequests <= 0) {
    throw new TypeError('maxRequests must be a positive integer');
  }

  // key -> array of request timestamps (ms), kept in ascending order.
  /** @type {Map<string, number[]>} */
  const hits = new Map();

  /**
   * Remove timestamps that fall outside the trailing window.
   * Timestamps are appended in time order, so all expired entries are a
   * contiguous prefix — find the first index still inside the window and slice.
   * @param {number[]} timestamps
   * @param {number} windowStart
   * @returns {number[]} timestamps within the window (may be empty)
   */
  function prune(timestamps, windowStart) {
    let i = 0;
    while (i < timestamps.length && timestamps[i] <= windowStart) {
      i++;
    }
    return i === 0 ? timestamps : timestamps.slice(i);
  }

  const middleware = function rateLimiter(req, res, next) {
    const key = keyGenerator(req);
    const now = Date.now();
    const windowStart = now - windowMs;

    const recent = prune(hits.get(key) || [], windowStart);
    const used = recent.length;

    if (used >= maxRequests) {
      // Over the limit. The window frees up when the OLDEST in-window request
      // exits the window: oldest timestamp + windowMs.
      const oldest = recent[0];
      const resetMs = oldest + windowMs;
      const retryAfterSec = Math.max(1, Math.ceil((resetMs - now) / 1000));

      // Persist the pruned list so we don't recompute stale entries next time.
      hits.set(key, recent);

      res.setHeader('X-RateLimit-Limit', maxRequests);
      res.setHeader('X-RateLimit-Remaining', 0);
      res.setHeader('X-RateLimit-Reset', Math.ceil(resetMs / 1000));
      res.setHeader('Retry-After', retryAfterSec);

      res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
      return; // do NOT call next()
    }

    // Under the limit: record this request and allow it through.
    recent.push(now);
    hits.set(key, recent);

    const remaining = maxRequests - recent.length;
    // The window's leading edge advances as the oldest request ages out.
    const resetMs = recent[0] + windowMs;

    res.setHeader('X-RateLimit-Limit', maxRequests);
    res.setHeader('X-RateLimit-Remaining', Math.max(0, remaining));
    res.setHeader('X-RateLimit-Reset', Math.ceil(resetMs / 1000));

    next();
  };

  // Periodic memory reclamation: drop keys whose every timestamp has aged out.
  const cleanupTimer = setInterval(() => {
    const windowStart = Date.now() - windowMs;
    for (const [key, timestamps] of hits) {
      const recent = prune(timestamps, windowStart);
      if (recent.length === 0) {
        hits.delete(key);
      } else if (recent.length !== timestamps.length) {
        hits.set(key, recent);
      }
    }
  }, cleanupMs);

  // Don't let the cleanup timer keep the Node process alive on its own.
  if (typeof cleanupTimer.unref === 'function') {
    cleanupTimer.unref();
  }

  // Clearable so tests / graceful shutdown can stop the timer entirely.
  middleware.close = function close() {
    clearInterval(cleanupTimer);
    hits.clear();
  };

  return middleware;
}

