 * Docker, Kubernetes ingress, etc.), you MUST call:
 *
 *     app.set('trust proxy', true);           // trust first proxy in chain
 *     // or
 *     app.set('trust proxy', 1);              // trust exactly 1 proxy
 *     app.set('trust proxy', 'loopback, 123.45.67.89'); // specific subnets
 *
 * See official docs: https://expressjs.com/en/guide/behind-proxies.html
 *
 * Without proper trust proxy configuration, all (or many) clients will appear
 * to share the same IP address. This will cause the rate limiter to incorrectly
 * throttle unrelated users as if they were a single client.
 *
 * Always configure trust proxy BEFORE mounting this middleware.
 * ---------------------------------------------------------------------------
 *
 * @module rate-limiter
 */

/**
 * Creates an Express middleware that enforces a sliding-window rate limit per IP.
 *
 * @param {Object} [options]
 * @param {number} [options.windowMs=60000]   - Size of the sliding window in milliseconds
 * @param {number} [options.maxRequests=100]  - Max requests allowed within the window
 * @returns {Function & { close: Function }} Express middleware function.
 *          The returned function also has a `.close()` method that stops the internal
 *          cleanup timer (call this on server shutdown to allow clean process exit).
 */
function createRateLimiter(options = {}) {
  const windowMs = Number.isFinite(options.windowMs) && options.windowMs > 0
    ? Math.floor(options.windowMs)
    : 60000;

  const maxRequests = Number.isFinite(options.maxRequests) && options.maxRequests > 0
    ? Math.floor(options.maxRequests)
    : 100;

  /** @type {Map<string, number[]>} ip -> array of request timestamps (ms since epoch) */
  const requests = new Map();

  // Periodic cleanup: every 60 seconds, drop IPs that have no recent activity.
  // This prevents unbounded memory growth when many different IPs hit the server.
  const CLEANUP_INTERVAL_MS = 60000;

  const cleanupInterval = setInterval(() => {
    const now = Date.now();
    const cutoff = now - windowMs;

    for (const [ip, timestamps] of requests.entries()) {
      // Keep only timestamps still inside the current window
      const recent = timestamps.filter(ts => ts > cutoff);

      if (recent.length === 0) {
        requests.delete(ip);
      } else if (recent.length < timestamps.length) {
        // Only write back if we actually removed entries (avoids unnecessary churn)
        requests.set(ip, recent);
      }
    }
  }, CLEANUP_INTERVAL_MS);

  // Allow the interval to be garbage-collected if no other event loop work remains.
  // This is a belt-and-suspenders measure; the primary mechanism is the explicit close().
  if (typeof cleanupInterval.unref === 'function') {
    cleanupInterval.unref();
  }

  /**
   * Stops the internal cleanup timer.
   * Call this when shutting down the server (e.g. in httpServer.close() callback
   * or process 'SIGTERM' handler) so the timer does not keep the Node process alive.
   */
  function close() {
    clearInterval(cleanupInterval);
  }

  /**
   * The actual Express middleware.
   * @param {import('express').Request} req
   * @param {import('express').Response} res
   * @param {import('express').NextFunction} next
   */
  function rateLimitMiddleware(req, res, next) {
    // Resolve client identifier.
    // Prefer req.ip (populated by Express after trust-proxy processing).
    // Fall back gracefully for environments where express is not fully configured.
    let ip = req.ip;

    if (!ip) {
      // Manual extraction (common when trust proxy is not configured or in tests)
      const forwarded = req.headers && (req.headers['x-forwarded-for'] || req.headers['x-real-ip']);
      if (forwarded) {
        // x-forwarded-for can be a comma-separated list: client, proxy1, proxy2
        ip = String(forwarded).split(',')[0].trim();
      }
    }

    if (!ip) {
      ip = (req.connection && req.connection.remoteAddress) ||
           (req.socket && req.socket.remoteAddress) ||
           'unknown';
    }

    // Normalize (strip IPv6 prefix if present, etc.)
    ip = String(ip).trim();

    const now = Date.now();
    const cutoff = now - windowMs;

    // Retrieve (or initialize) the list of timestamps for this IP
    let timestamps = requests.get(ip) || [];

    // === TRUE SLIDING WINDOW PRUNING ===
    // Remove every timestamp that is older than (now - windowMs).
    // This is the heart of the algorithm: the window "slides" continuously
    // with wall-clock time rather than resetting on a fixed schedule.
    timestamps = timestamps.filter(ts => ts > cutoff);

    // Check against the limit using the *current* count of still-valid requests.
    if (timestamps.length >= maxRequests) {
      // Compute how long the caller must wait until the oldest request falls
      // out of the window, freeing up one slot.
      const oldest = timestamps[0];
      const retryAfterMs = (oldest + windowMs) - now;
      const retryAfter = Math.max(1, Math.ceil(retryAfterMs / 1000));

      res.set('Retry-After', String(retryAfter));

      return res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter
      });
    }

    // Request is allowed: record the current timestamp
    timestamps.push(now);
    requests.set(ip, timestamps);

    // === Rate limit response headers (only set on successful/allowed requests) ===
    res.set('X-RateLimit-Limit', String(maxRequests));

    // Remaining quota after this request has been counted.
    const remaining = maxRequests - timestamps.length;
    res.set('X-RateLimit-Remaining', String(remaining));

    // X-RateLimit-Reset: Unix epoch seconds when the oldest request in the
    // current window will expire (i.e. the moment the count will drop by one).
    // This is the semantically correct value for a sliding window.
    const resetEpochSec = Math.ceil((timestamps[0] + windowMs) / 1000);
    res.set('X-RateLimit-Reset', String(resetEpochSec));

    next();
  }

  // Expose the cleanup method directly on the middleware function.
  // Usage: const limiter = createRateLimiter();  app.use(limiter);  ...  limiter.close();
  rateLimitMiddleware.close = close;

  // Exposed for testing / introspection only (not part of public API)
  rateLimitMiddleware._store = requests;

  return rateLimitMiddleware;
}

module.exports = {
  createRateLimiter
};
